    .filter(r=>String(r.type||'').toLowerCase()==='lodging' && String(r.status||'').toLowerCase()!=='cancelled')
    .map(r=>({...r, latitude:numOrNull(r.latitude), longitude:numOrNull(r.longitude)}))
    .find(r=>r.latitude!==null && r.longitude!==null) || null;
}
function applyLodgingStopLocations(){
  stops.forEach((s,i)=>{
    const loc=lodgingLocationForStop(i);
    if(loc){ s[1]=loc.latitude; s[2]=loc.longitude; s[6]=Object.assign({},s[6]||{},{lodgingLocation:loc}); }
    else { s[1]=originalStopLocations[i][0]; s[2]=originalStopLocations[i][1]; if(s[6]?.lodgingLocation) delete s[6].lodgingLocation; }
    if(markers[i]) markers[i].setLatLng([s[1],s[2]]);
  });
}
function sortedReservations(){ return [...tripData.reservations].sort((a,b)=>{ const as=a.stop_id==null||a.stop_id===''?999999:Number(a.stop_id); const bs=b.stop_id==null||b.stop_id===''?999999:Number(b.stop_id); if(as!==bs) return as-bs; return String(a.reservation_date||'9999-12-31').localeCompare(String(b.reservation_date||'9999-12-31')) || String(a.reservation_time||'23:59:59').localeCompare(String(b.reservation_time||'23:59:59')) || String(a.title||'').localeCompare(String(b.title||'')); }); }
function panelHtml(title, body, open=false){ return `<details ${open?'open':''}><summary>${title}</summary><div class="panel-body">${body}</div></details>`; }
function popupHtml(s,i){const meta=s[6]||{}; const thumb=meta.thumbnail?`<img class="popup-thumb" src="${meta.thumbnail}" alt="${meta.thumbnailAlt||s[0]}" loading="lazy">`:''; const site=meta.website?` · <a href="${meta.website}" target="_blank" rel="noopener">Official site</a>`:''; const itemRows=itemsForStop(i).map(x=>`<li class="item-row"><span>${esc(x.item_text)}</span>${tripData.isAdmin?`<button data-delete-item="${x.id}" type="button">×</button>`:''}</li>`).join(''); const addItem=tripData.isAdmin?`<form class="form-grid add-item-form" data-stop="${stopDataId(i)}" data-index="${i}"><input name="item_text" placeholder="Add note/item for this stop"><button type="submit">Add</button></form>`:''; const resRows=reservationsForStop(i).map(r=>`<li><b>${esc(r.title)}</b>${r.reservation_date?` — ${esc(r.reservation_date)}`:''}${r.confirmation?`<br><span class="tiny">Confirmation: ${esc(r.confirmation)}</span>`:''}${r.notes?`<br><span>${esc(r.notes)}</span>`:''}</li>`).join(''); return `${thumb}<div class="popup-title">${s[0]}</div><div><span class="date-badge">${stopDate(i)}</span><span class="temp-badge">${tempText(i)}</span></div><div class="popup-stay"><b>${meta.type==='attraction'?'Type':'Stay'}:</b> ${s[3]}</div><b>Things to do:</b><ul class="popup-list">${s[4].map(t=>`<li>${t}</li>`).join('')}</ul><p class="tiny">${tempDetail(i)}</p><p><a href="${mapsUrl(s)}" target="_blank" rel="noopener">Google Maps</a> · <a href="${appleMapsUrl(s)}" target="_blank" rel="noopener">Apple Maps</a> · <a href="${weatherUrl(s)}" target="_blank" rel="noopener">Weather</a>${site}</p><div class="popup-section"><h4>Stop notes</h4><ul class="mini-list">${itemRows||'<li class="tiny">No extra notes yet.</li>'}</ul>${addItem}</div><div class="popup-section"><h4>Reservations for this stop</h4><ul class="mini-list">${resRows||'<li class="tiny">No linked reservations yet.</li>'}</ul></div>`}
function refreshPopups(){ markers.forEach((m,i)=>{ if(stops[i]) m.setPopupContent(popupHtml(stops[i],i)); }); }
function popupPadding(){ return window.innerWidth < 860 ? L.point(24, 96) : L.point(28, 72); }
function panPopupFullyIntoView(){
  const popup = document.querySelector('.leaflet-popup');
  if(!popup) return;
  const close = popup.querySelector('.leaflet-popup-close-button');
  const popupRect = popup.getBoundingClientRect();
  const closeRect = close ? close.getBoundingClientRect() : popupRect;
  const rect = {
    left: Math.min(popupRect.left, closeRect.left),
    right: Math.max(popupRect.right, closeRect.right),
    top: Math.min(popupRect.top, closeRect.top),
    bottom: Math.max(popupRect.bottom, closeRect.bottom)
  };
  const pad = window.innerWidth < 860 ? 28 : 14;
  const topPad = window.innerWidth < 860 ? 82 : 54;
  let dx = 0, dy = 0;
  if(rect.left < pad) dx = rect.left - pad;
  else if(rect.right > window.innerWidth - pad) dx = rect.right - (window.innerWidth - pad);
  if(rect.top < topPad) dy = rect.top - topPad;
  else if(rect.bottom > window.innerHeight - pad) dy = rect.bottom - (window.innerHeight - pad);
  if(dx || dy) map.panBy([dx, dy], {animate:true, duration:.2});
}
map.on('popupopen', () => setTimeout(panPopupFullyIntoView, 80));
function focusStop(i, zoom=10){
  activeIndex = i; renderItinerary(); const s=stops[i]; map.flyTo([s[1],s[2]], zoom, {duration:.75}); markers[i].openPopup();
  setTimeout(panPopupFullyIntoView, 850);
  if (window.innerWidth < 860) document.getElementById('map').scrollIntoView({behavior:'smooth', block:'start'});
}
function matches(s){
  const q = searchEl.value.trim().toLowerCase(); const blob = [s[0],s[3],...s[4],...s[5]].join(' ').toLowerCase();
  return !q || blob.includes(q);
}
function cardReservationsHtml(i){
  const rows = reservationsForStop(i);
  if(!rows.length) return '';
  return `<div class="card-reservations"><b>Reservations</b><ul>${rows.map(r=>`<li>${esc(r.title)}${r.reservation_date?` — ${esc(r.reservation_date)}`:''}${r.reservation_time?` ${esc(r.reservation_time)}`:''}</li>`).join('')}</ul></div>`;
}
function renderItinerary(){
  const items = stops.map((s,i)=>({s,i})).filter(x=>matches(x.s));
  if(!items.length){itineraryEl.innerHTML='<div class="empty">No stops match that search/filter.</div>'; return;}
  itineraryEl.innerHTML = items.map(({s,i})=>`<article class="card ${i===activeIndex?'active':''}" data-index="${i}"><div class="card-head"><div class="pin">${String(i).padStart(2,'0')}</div><div><div><span class="date-badge">${stopDate(i)}</span><span class="temp-badge">${tempText(i)}</span></div><h2>${s[0]}</h2><div class="stay">${s[3]}</div></div></div><ul class="activities">${s[4].map(a=>`<li>${a}</li>`).join('')}</ul>${cardReservationsHtml(i)}<div class="actions"><a href="${mapsUrl(s)}" target="_blank" rel="noopener" onclick="event.stopPropagation()">Google Maps</a><a href="${appleMapsUrl(s)}" target="_blank" rel="noopener" onclick="event.stopPropagation()">Apple Maps</a><a href="${weatherUrl(s)}" target="_blank" rel="noopener" onclick="event.stopPropagation()">Weather</a><a href="https://www.google.com/search?q=${encodeURIComponent(s[0]+' lodging restaurants things to do')}" target="_blank" rel="noopener" onclick="event.stopPropagation()">Research stop</a></div></article>`).join('');
  itineraryEl.querySelectorAll('.card').forEach(card=>card.addEventListener('click',()=>focusStop(Number(card.dataset.index))));
}
stops.forEach((s,i)=>{
  const meta=s[6]||{};
  const markerOptions={title:s[0]};
  if(meta.icon){ markerOptions.icon=L.divIcon({className:'tram-icon',html:meta.icon,iconSize:[34,34],iconAnchor:[17,17],popupAnchor:[0,-18]}); }
  const marker = L.marker([s[1],s[2]],markerOptions).addTo(map).bindPopup(popupHtml(s,i),{maxWidth:390,autoPan:true,keepInView:true,autoPanPaddingTopLeft:popupPadding(),autoPanPaddingBottomRight:popupPadding()});
  marker.on('click',()=>{activeIndex=i; renderItinerary();}); markers.push(marker); bounds.push([s[1],s[2]]);
});
function avenuePopup(point){return `<div class="popup-title">${point.label}</div><div class="popup-stay"><b>Scenic drive:</b> Avenue of the Giants</div><p>${point.note}</p><p><a href="https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(point.lat+','+point.lng)}" target="_blank" rel="noopener">Google Maps</a> · <a href="https://maps.apple.com/?ll=${encodeURIComponent(point.lat+','+point.lng)}&q=${encodeURIComponent(point.label)}" target="_blank" rel="noopener">Apple Maps</a> · <a href="https://aveofthegiants.com/" target="_blank" rel="noopener">Avenue guide</a></p>`}
const avenueHighlight = L.polyline(avenueOfTheGiants.line,{color:'#2f7d55',weight:8,opacity:.82,dashArray:'12,8'}).addTo(map).bindTooltip('Avenue of the Giants scenic redwood drive');
routeLayers.push(avenueHighlight);
avenueHighlight.on('click',()=>setTimeout(panPopupFullyIntoView,80));
[avenueOfTheGiants.start, avenueOfTheGiants.end].forEach((point,idx)=>{
  const iconClass = idx===0 ? 'poi-icon avenue-start' : 'poi-icon avenue-end';
  const marker = L.marker([point.lat,point.lng],{title:point.name,icon:L.divIcon({className:iconClass,html:point.icon,iconSize:[34,34],iconAnchor:[17,17],popupAnchor:[0,-18]})}).addTo(map).bindPopup(avenuePopup(point),{maxWidth:360,autoPan:true,keepInView:true,autoPanPaddingTopLeft:popupPadding(),autoPanPaddingBottomRight:popupPadding()});
  markers.push(marker); bounds.push([point.lat,point.lng]);
});
avenueOfTheGiants.line.forEach(p=>bounds.push(p));
let complete=0, errors=0;
function updateStatus(){
  const totalMiles = mapboxRoutes.reduce((sum,r)=>sum+(r.distance_miles||0),0).toFixed(0);
  const totalHours = mapboxRoutes.reduce((sum,r)=>sum+(r.duration_hours||0),0).toFixed(1);
  if(errors===0){statusEl.textContent=`Mapbox routes loaded: ${mapboxRoutes.length} segments, about ${totalMiles} miles / ${totalHours} driving hours. Planning map only; verify closures and navigation before driving.`;}
  else{statusEl.textContent=`Mapbox routes loaded with ${errors} fallback segment(s). Verify the affected route legs before driving.`;}
}
function effectiveRoutePointForOriginal(p,isEndpoint=false){
  const tolerance=isEndpoint?0.20:0.00001;
  for(let i=0;i<originalStopLocations.length;i++){
    const o=originalStopLocations[i];
    if(Math.abs(Number(p[0])-o[0])<tolerance && Math.abs(Number(p[1])-o[1])<tolerance) return [Number(stops[i][1]),Number(stops[i][2])];
  }
  return [Number(p[0]),Number(p[1])];
}
const segmentEndpointStopIndexes = [[0,1],[1,3],[3,4],[4,5],[5,6],[6,7],[7,8],[8,8],[8,9],[9,10],[10,11],[11,12]];
function routeEndpointForSegmentPoint(segmentIndex, pointIndex, lastIndex, originalPoint){
  const endpointStops=segmentEndpointStopIndexes[segmentIndex];
  if(endpointStops && pointIndex===0 && stops[endpointStops[0]]) return [Number(stops[endpointStops[0]][1]), Number(stops[endpointStops[0]][2])];
  if(endpointStops && pointIndex===lastIndex && stops[endpointStops[1]]) return [Number(stops[endpointStops[1]][1]), Number(stops[endpointStops[1]][2])];
  return effectiveRoutePointForOriginal(originalPoint, pointIndex===0||pointIndex===lastIndex);
}
function applyLodgingRouteWaypoints(){
  segments.forEach((seg,idx)=>{ const last=originalSegments[idx][1].length-1; seg[1]=originalSegments[idx][1].map((p,pidx)=>routeEndpointForSegmentPoint(idx,pidx,last,p)); });
}
async function fetchMapboxRouteForSegment(seg, idx){
  const coords=seg[1].map(p=>`${p[1]},${p[0]}`).join(';');
  const url=`https://api.mapbox.com/directions/v5/mapbox/driving/${coords}?alternatives=false&geometries=geojson&overview=full&steps=false&access_token=${mapboxToken}`;
  const json=await fetch(url).then(r=>r.ok?r.json():null).catch(()=>null);
  const route=json?.routes?.[0];
  if(!route?.geometry?.coordinates) return null;
  return {name:seg[0],geometry:route.geometry,distance_miles:(route.distance||0)/1609.344,duration_hours:(route.duration||0)/3600};
}
async function renderDrivingRoutes(refreshFromMapbox=false){
  drivingRouteLayers.splice(0).forEach(layer=>map.removeLayer(layer));
  complete=0; errors=0;
  const fitPoints=[];
  for(const s of stops) fitPoints.push([s[1],s[2]]);
  if(avenueOfTheGiants?.line) avenueOfTheGiants.line.forEach(p=>fitPoints.push(p));
  for(let idx=0; idx<segments.length; idx++){
    const seg=segments[idx];
    const name=seg[0], wps=seg[1].map(p=>L.latLng(p[0],p[1])); wps.forEach(p=>fitPoints.push([p.lat,p.lng]));
    const color = colors[idx % colors.length];
    let route = mapboxRoutes[idx];
    if(refreshFromMapbox) {
      const freshRoute = await fetchMapboxRouteForSegment(seg, idx);
      route = freshRoute;
      if(freshRoute) mapboxRoutes[idx]=freshRoute;
    }
    if(route && route.geometry && route.geometry.coordinates){
      const latlngs = route.geometry.coordinates.map(c=>[c[1],c[0]]);
      const layer = L.polyline(latlngs,{color,opacity:.9,weight:5}).addTo(map).bindTooltip(`${route.name}<br>${Number(route.distance_miles||0).toFixed(0)} miles · ${Number(route.duration_hours||0).toFixed(1)} driving hours`);
      drivingRouteLayers.push(layer); routeLayers.push(layer); latlngs.forEach(p=>fitPoints.push(p)); complete++;
    } else {
      errors++;
      const fallback=L.polyline(wps,{color:'#777',weight:3,opacity:.45,dashArray:'7,8'}).addTo(map).bindTooltip(name+' — fallback line');
      drivingRouteLayers.push(fallback); routeLayers.push(fallback);
    }
  }
  routeBounds=L.latLngBounds(fitPoints);
  updateStatus();
}
renderDrivingRoutes(false);
let photoLayer = L.layerGroup().addTo(map);
function routeAppleLink(idx){ const seg=segments[idx]; if(!seg) return '#'; const pts=seg[1].map(p=>`${p[0]},${p[1]}`).join('&daddr='); return 'https://maps.apple.com/?saddr=' + pts; }
function renderPanels(){
  document.getElementById('datesPanel').innerHTML = panelHtml('Trip dates', `<p><b>Fly out / Day 0:</b> ${fmtDate(tripStart)}</p><p><b>Finish:</b> ${fmtDate(addDays(tripStart,18))}</p><p class="auth-note">Dates are shown on every stop card and popup. Apple Maps, Google Maps, and weather links are available per stop.</p>`, true);
